[OK] <!DOCTYPE html>
<html lang="pt-BR">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Matrix Rain Background</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            min-height: 100vh;
            font-family: 'Courier New', monospace;
            overflow: hidden;
            position: relative;
            background: #000;
        }

        /* Matrix Rain Background */
        .matrix-bg {
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            z-index: -1;
            overflow: hidden;
            pointer-events: none;
        }

        .matrix-bg canvas {
            display: block;
        }

        /* Overlay for better text readability */
        .overlay {
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background: rgba(0, 0, 0, 0.6);
            backdrop-filter: blur(3px);
            z-index: 0;
        }

        .content {
            position: relative;
            z-index: 1;
            padding: 2rem;
            color: #00ff41;
            text-align: center;
        }

        h1 {
            font-size: 4rem;
            margin-bottom: 1rem;
            text-shadow: 0 0 10px #00ff41, 0 0 20px #00ff41;
            font-family: 'Courier New', monospace;
            animation: text-fade 3s ease-in-out infinite alternate;
        }

        p {
            font-size: 1.2rem;
            opacity: 0.9;
            font-family: 'Courier New', monospace;
        }

        @keyframes text-fade {
            from {
                opacity: 0.8;
            }
            to {
                opacity: 1;
            }
        }

        /* CRT scanline effect */
        .crt-lines {
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background: repeating-linear-gradient(
                0deg,
                rgba(0, 0, 0, 0.15),
                rgba(0, 0, 0, 0.15) 1px,
                transparent 1px,
                transparent 2px
            );
            pointer-events: none;
            z-index: 10;
        }

        /* Vignette effect */
        .vignette {
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background: radial-gradient(
                circle, 
                transparent 50%,
                rgba(0, 0, 0, 0.8) 100%
            );
            pointer-events: none;
            z-index: 11;
        }
    </style>
</head>
<body>
    <div class="gradient-bg"></div>
    <div class="overlay"></div>
    <div class="content">
        <h1>🌈 Dynamic Gradient Background</h1>
        <p>Smooth color transitions with continuous animation</p>
    </div>

    <script>
        // Advanced gradient animation with dynamic color generation
        class GradientAnimation {
            constructor() {
                this.colors = [];
                this.currentHue = 0;
                this.hueSpeed = 0.5;
                this.gradientElement = document.querySelector('.gradient-bg');
                this.init();
            }

            init() {
                // Generate a vibrant color palette
                this.colors = [
                    '#1a1a2e', '#16213e', '#0f3460',
                    '#533483', '#6c5ce7', '#a29bfe',
                    '#fd79a8', '#fdcb6e', '#e17055',
                    '#00b894', '#0984e3', '#6c5ce7',
                    '#ff7675', '#74b9ff', '#55efc4',
                    '#ffeaa7', '#fab1a0', '#a29bfe'
                ];

                // Apply initial gradient
                this.updateGradient();

                // Start animation
                this.animate();
            }


